/* Define variables on :root for global access */
:root {
  --color-primary: #3b82f6;
  --color-primary-dark: #1d4ed8;
  --color-text: #1f2937;
  --color-bg: #ffffff;
  --font-sans: 'Inter', system-ui, sans-serif;
  --spacing-sm: 0.5rem;
  --spacing-md: 1rem;
  --spacing-lg: 2rem;
  --radius: 8px;
  --shadow: 0 1px 3px rgba(0, 0, 0, 0.12);
}

/* Dark mode with a single class swap */
[data-theme='dark'] {
  --color-text: #f9fafb;
  --color-bg: #111827;
  --shadow: 0 1px 3px rgba(0, 0, 0, 0.5);
}

/* Use variables anywhere */
.button {
  background: var(--color-primary);
  color: white;
  padding: var(--spacing-sm) var(--spacing-md);
  border-radius: var(--radius);
  font-family: var(--font-sans);
  border: none;
  cursor: pointer;
}

.button:hover {
  background: var(--color-primary-dark);
}

/* Transition: smooth changes on state change */
.button {
  background: #3b82f6;
  transition: background 200ms ease, transform 150ms ease;
}

.button:hover {
  background: #1d4ed8;
  transform: translateY(-1px);
}

.button:active {
  transform: translateY(0);
}

/* Keyframe animation: complex multi-step animations */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.card {
  animation: fadeInUp 400ms ease-out;
}

/* Spinner animation */
@keyframes spin {
  to { transform: rotate(360deg); }
}

.spinner {
  width: 24px;
  height: 24px;
  border: 3px solid #e5e7eb;
  border-top-color: #3b82f6;
  border-radius: 50%;
  animation: spin 600ms linear infinite;
}

/* Respect user preferences for reduced motion */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

/* Block: .card */
.card {
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 1.5rem;
}

/* Element: .card__title (part of the card) */
.card__title {
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: 0.5rem;
}

.card__body {
  color: #6b7280;
  line-height: 1.6;
}

.card__footer {
  margin-top: 1rem;
  border-top: 1px solid #e5e7eb;
  padding-top: 1rem;
}

/* Modifier: .card--featured (a variation of the card) */
.card--featured {
  border-color: #3b82f6;
  box-shadow: 0 4px 6px rgba(59, 130, 246, 0.1);
}

.card--compact {
  padding: 0.75rem;
}
